import React from 'react';

function About() {
    return (
        <div>
        <h1>About</h1>
        <p>We are an organization, dedicated to tailoring and providing up-to-date information regarding different pets and their types</p>
        <ul>
        <li>Our organization is dedicated to providing the best information about pets</li>
        <li>We have been in business for over 20 years</li>
        </ul>
        </div>
    );
}
export default About;
